theme.scss:
@import "bootstrap";
// Add global styling here for built in self-serve modules
// These styles will also be applied to your custom modules

// DO NOT REFERENCE EXTERNAL FILES HERE
// This theme file will be used as-is and external references will not
// be compiled or resolved in any way. You can however reference THIS file
// in your custom modules.

// Import fonts here, do not import fonts in individual module files
// @import url('[FONT URL HERE]');
@import url('https://cdnjs.cloudflare.com/ajax/libs/font-awesome/4.2.0/css/font-awesome.min.css');
// @import url(https://fonts.googleapis.com/css?family=Oswald:300,400,500,700&display=swap);
@import url('https://fonts.googleapis.com/css2?family=Oswald:wght@300;400;500;600;700');

body {
  font-family: 'Oswald';
  font-size: 20px;
  line-height: 26px;
  font-weight: 300;
  position: relative;
  background-image: none!important;
  background-color: #FFF0C9;
  background-repeat: none;
}

h1,h2,h3,h4,h5,h6
{
  font-family: 'Oswald';
  font-weight: 500;
}

a
{
  font-family: 'Oswald';
}

button,
.btn
{
  font-size: 14px;
  line-height: 20px;
  padding: 8px 14px;
  font-weight: 400;
  border: none;

  &:hover
  {
    box-shadow: 0 20px 38px rgba(0, 0, 0, 0.16)!important;
    transform: translateY(-3px);
  }

  &:focus
  {
    text-decoration: initial !important;
    outline: 2px dotted #003976 !important;
    opacity: 0.65;
    transform: translateY(-3px);
  }
}

a:focus {
  text-decoration: underline !important;
  text-decoration-style: dotted !important;
}

