.paragraph {font-family:'RB Rational Neue Narrow'!important;}

address, .hours-body, .Location-Name lp-param lp-param-locationName{font-family:'RB Rational Neue Narrow'!important;font-size:20px;line-height:26px; position:relative;background-repeat:repeat}

h1,h2,h3,h4,h5,h6, .h1, .h2, .h3, .h4, .h5, .h6{font-family:'RB Multima'!important; text-transform:uppercase;}

a{font-family:'RB Multima'}

button,.btn{font-family:'RB Multima'!important;font-size:14px;line-height:20px;padding:8px 14px;font-weight:400;border:none}
// Choose the color overlay on the image
$overlay-color: transparentize(#0045bd, 1);
