body {
  background-image:none!important;
  background-color: #FFF0C9!important;
}

.location-name {
  font-weight: bold;
  color:#0045BD;
}

//displays phonenumber as button on smaller devices
.phone-link {
  @media (min-width: 768px) {
    display: none;
  }
}

.phone-text {
  @media (max-width: 768px) {
    display: none;
    color:#0045BD;
    font-family: 'RB Multima'
  }
}

.arrow-img {
    transform: rotate(-180deg);
    margin-bottom: 10px;
}

.collapsed .arrow-img {
    transform: rotate(0deg);
    margin-bottom: 0px;
}

.info-header {

}

.hours-header {

}
//Make "Open - Close" text transparent
.primary-open-today {
    opacity: 0%;

}

.secondary-hours-header {
    margin-top: $spacer;
}

.secondary-open-today {
    font-size: 16px;
    text-decoration: none;
    color: inherit;
}

.arrow-img {
    margin-left: 0.5rem;
    padding-bottom: 5px;
}

.ctas {
  margin-top: 1rem;

  .btn {
    @media (min-width: 768px) {
      margin-bottom: 0.25rem;
      border-radius: 20px;
      background-color: #0045BD;

      &:not(:last-child) {
        margin-right: 0.25rem;
      }
    }
    @media (max-width: 768px) {
      display: block;
      margin-bottom: 0.25rem;
    }
  }

  .directions-cta {}

  .secondary-cta {}
}

//display the current day as bold
.hours {
  .hours-row-today {
    font-weight: bold;
  }

  .hours-label {
    vertical-align: top;
    padding-right: 10px;
  }

}

.map {
  height: 300px;
}

//Make Country transparent
.c-address-country-name {
    opacity: 0%;
}

