module.scss:
@font-face {
  font-family: 'RB Rational Neue Narrow';
  src:
    url('https://skylinechil.wpenginepowered.com/wp-content/themes/skyline-chili-theme/dist/fonts/RBRationalNeueNarrow-SemiBold.woff2') format('woff2') ;
  font-weight: 600;
  font-style: normal;
  font-display: swap;
}



$background-color: #0045BD;
$link-color: #FFFAED;
$mobile-breakpoint: 768px;

background-color: $background-color;
padding: 2rem 0;

.footer-links {
    justify-content: start;
    padding-left: 0rem;

    .footer-link {
        padding: 0rem .5rem;
        text-decoration: underline;
        color: $link-color;

        &:first-child {
            padding-left: 0px;
        }

        &:hover {
            text-decoration: none;
        }
    }
}

.col:empty {
    display: none;
}

.caption-text {
    font-family: 'RB Rational Neue Narrow';
    color:#FFFAED;
    text-align: center;
}

@media (max-width: $mobile-breakpoint) {
    text-align: center;

    .caption-text {
        justify-content: center;
    }

    .footer-links {
        flex-direction: column;
        align-items: center;

        .footer-link {
            padding: 0.5rem 0rem;
        }
    }
}

.row {
    display: block;
}

.social-icon {
    display: block;
    align-items: center;
    justify-content: center;
    height: 45px;
    width: 45px;

}

module.default_scss:
$background-color: #e9ecef;
$link-color: #212529;
$mobile-breakpoint: 768px;

background-color: $background-color;
padding: 2rem 0;

.footer-links {
    display: flex;
    justify-content: start;
    padding-left: 0rem;

    .footer-link {
        padding: 0rem .5rem;
        text-decoration: underline;
        color: $link-color;

        &:first-child {
            padding-left: 0px;
        }

        &:hover {
            text-decoration: none;
        }
    }
}

.col:empty {
    display: none;
}

.caption-text {
    padding-top: 1rem;
    justify-content: start;
}

@media (max-width: $mobile-breakpoint) {
    text-align: center;

    .caption-text {
        justify-content: center;
    }

    .footer-links {
        flex-direction: column;
        align-items: center;

        .footer-link {
            padding: 0.5rem 0rem;
        }
    }
}

.social-icon {
    align-items: center;
    display: flex;
    justify-content: center;
    height: 45px;
    width: 45px;

    .icon-img {
        filter: invert(1); // make it black
    }
}

